mapper.select:
select task_department_checkpoint_id, company_id, task_id, department_id, status, require_evidence,
       evidence_note, evidence_ref, confirmed_by, confirmed_at, created_at, updated_at
from task_department_checkpoints
where company_id = #{companyId,jdbcType=VARCHAR}
  and task_id = #{taskId,jdbcType=VARCHAR}
order by created_at asc

select task_department_checkpoint_id, company_id, task_id, department_id, status, require_evidence,
       evidence_note, evidence_ref, confirmed_by, confirmed_at, created_at, updated_at
from task_department_checkpoints
where company_id = #{companyId,jdbcType=VARCHAR}
  and task_id = #{taskId,jdbcType=VARCHAR}
  and department_id = #{departmentId,jdbcType=VARCHAR}
limit 1

select count(1)
from task_department_checkpoints
where company_id = #{companyId,jdbcType=VARCHAR}
  and task_id = #{taskId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), 'PENDING')) != 'CONFIRMED'

select t.task_id, c.onboarding_id, t.checklist_id, c.name as checklist_name, t.title, t.status as task_status, t.due_date, t.assigned_user_id, t.assigned_department_id, dcp.status as checkpoint_status, dcp.require_evidence, dcp.confirmed_at from task_department_checkpoints dcp join task_instances t on t.company_id = dcp.company_id and t.task_id = dcp.task_id join checklist_instances c on c.company_id = t.company_id and c.checklist_id = t.checklist_id where dcp.company_id = #{companyId,jdbcType=VARCHAR} and dcp.department_id = #{departmentId,jdbcType=VARCHAR}
and upper(coalesce(trim(dcp.status), 'PENDING')) = #{checkpointStatus,jdbcType=VARCHAR}
and upper(coalesce(trim(dcp.status), 'PENDING')) != 'CONFIRMED'
order by case when t.due_date is null then 1 else 0 end asc, t.due_date asc, t.created_at desc limit #{limit} offset #{offset}

select count(1)
from task_department_checkpoints dcp
join task_instances t
  on t.company_id = dcp.company_id and t.task_id = dcp.task_id
where dcp.company_id = #{companyId,jdbcType=VARCHAR}
  and dcp.department_id = #{departmentId,jdbcType=VARCHAR}


      and upper(coalesce(trim(dcp.status), 'PENDING')) = #{checkpointStatus,jdbcType=VARCHAR}


      and upper(coalesce(trim(dcp.status), 'PENDING')) != 'CONFIRMED'
